module top_module(
  input [2:0] op,
  input [7:0] a,
  input [7:0] b,
  input [4:0] reg_addr,
  input reg_write,
  output reg [7:0] result  // Change wire to reg
);reg [7:0] input_data;
  reg [7:0] neg_b;

  always @(*) begin
    case(op)
      3'b000: input_data = a + b;
      3'b001: begin
                 neg_b = ~b + 1;
                 input_data = a + neg_b;
               end
      3'b010: input_data = a & b;
      3'b011: input_data = a | b;
      3'b100: input_data = a ^ b;
      default: input_data = 8'h00;
    endcase
  end

  always @(posedge reg_write) begin
    if (reg_write) begin
      result <= input_data;  // Update only once based on input_data
    end
  end

endmodule
